module top_module(din, reset_clk, rst, q, se, si, so);parameter SIZE = 1;

input	[SIZE-1:0]	din ;	
input			reset_clk ;	
input			rst ;	

output	[SIZE-1:0]	q ;	

input			se ;	
input	[SIZE-1:0]	si ;	
output	[SIZE-1:0]	so ;	

reg 	[SIZE-1:0]	q ;

`ifdef NO_SCAN
always @ (posedge reset_clk)
	q[SIZE-1:0]  <= ((rst) ? {SIZE{1'b0}}  : din[SIZE-1:0] );
`else


always @ (posedge reset_clk)

	q[SIZE-1:0]  <= se ? si[SIZE-1:0] : ((rst) ? {SIZE{1'b0}}  : din[SIZE-1:0] );

assign so[SIZE-1:0] = q[SIZE-1:0] ;
`endif

endmodule
